//go:generate ../../../tools/readme_config_includer/generator
//go:build linux && amd64

package turbostat

import (
	"bufio"
	_ "embed"
	"errors"
	"fmt"
	"io"
	"regexp"
	"strconv"
	"strings"
	"time"

	"github.com/influxdata/telegraf"
	"github.com/influxdata/telegraf/config"
	"github.com/influxdata/telegraf/internal/process"
	"github.com/influxdata/telegraf/plugins/inputs"
)

//go:embed sample.conf
var sampleConfig string

var (
	// Mapping from abbreviations to full words.
	abbreviations = map[string]string{
		"%":    "percent",
		"+":    "plus",
		"-":    "minus",
		"watt": "power_watt",
		"mhz":  "frequency_mhz",
		"tmp":  "temperature_celsius",
		"thr":  "throttle",
		"avg":  "average",
		"cor":  "core",
		"bzy":  "busy",
		"pkg":  "package",
		"sys":  "system",
		"unc":  "uncore",
		"u":    "uncore",
		"a":    "actual",
		"j":    "energy_joule",
	}

	// Replacer to add underscores around certain words.
	replacer = strings.NewReplacer(
		"Watt", "_Watt_",
		"MHz", "_MHz_",
		"Tmp", "_Tmp_",
		"Thr", "_Thr_",
		"GFX", "_GFX_",
		"SAM", "_SAM_",
	)

	// Regex to split a string into alphanumeric tokens, percent (%), plus (+), and minus (-).
	splitter = regexp.MustCompile(`[0-9a-zA-Z]+|\%|\+|\-`)
)

type Turbostat struct {
	UseSudo  bool            `toml:"use_sudo"`
	Path     string          `toml:"path"`
	Interval config.Duration `toml:"interval"`
	Log      telegraf.Logger `toml:"-"`

	command []string
	process *process.Process
}

type column struct {
	name   string
	isTag  bool
	isTime bool
}

func (*Turbostat) SampleConfig() string {
	return sampleConfig
}

func (t *Turbostat) Init() error {
	if t.Path == "" {
		t.Path = "turbostat"
	}

	if t.Interval <= 0 {
		t.Interval = config.Duration(10 * time.Second)
	}

	// Build the command line to spawn Turbostat.
	t.command = make([]string, 0, 10)
	if t.UseSudo {
		t.command = append(t.command, "sudo")
	}
	interval := strconv.FormatFloat(time.Duration(t.Interval).Seconds(), 'f', -1, 64)
	t.command = append(t.command, t.Path, "--quiet", "--interval", interval, "--show", "all")

	return nil
}

func (t *Turbostat) Start(acc telegraf.Accumulator) error {
	var err error
	t.process, err = process.New(t.command, nil)
	if err != nil {
		return fmt.Errorf("failed to create process %s: %w", t.command, err)
	}

	// Read error lines from Turbostat stderr and add them to the accumulator.
	t.process.ReadStderrFn = func(r io.Reader) {
		scanner := bufio.NewScanner(r)
		for scanner.Scan() {
			acc.AddError(errors.New(scanner.Text()))
		}
		acc.AddError(scanner.Err())
	}

	// Read metrics from Turbostat stdout and add them to the accumulator.
	// Add any error to the accumulator and continue processing the next lines.
	t.process.ReadStdoutFn = func(r io.Reader) {
		scanner := bufio.NewScanner(r)
		if !scanner.Scan() {
			acc.AddError(scanner.Err())
			return
		}
		header := scanner.Text()
		columns := make([]column, 0, 50)
		for _, s := range strings.Fields(header) {
			columns = append(columns, createColumn(s))
		}
		for scanner.Scan() {
			line := scanner.Text()
			if line == header {
				continue
			}
			values := strings.Fields(line)
			acc.AddError(processValues(acc, columns, values))
		}
		acc.AddError(scanner.Err())
	}

	t.process.StopOnError = false
	t.process.Log = t.Log

	if err = t.process.Start(); err != nil {
		return fmt.Errorf("failed to start process %s: %w", t.command, err)
	}
	return nil
}

func (t *Turbostat) Stop() {
	t.process.Stop()
}

func (*Turbostat) Gather(telegraf.Accumulator) error {
	return nil
}

// Creates a metric from columns and values, and adds it to an accumulator.
func processValues(acc telegraf.Accumulator, columns []column, values []string) error {
	if len(values) > len(columns) {
		return fmt.Errorf("too many values: %d columns, %d values", len(columns), len(values))
	}
	tags := make(map[string]string, len(values))
	fields := make(map[string]any, len(values))
	timestamp := time.Now()
	for i, value := range values {
		column := columns[i]
		switch {
		case column.isTime:
			f, err := strconv.ParseFloat(value, 64)
			if err != nil {
				return fmt.Errorf("unable to parse time: %w", err)
			}
			timestamp = time.Unix(0, int64(f*1e9))
		case column.isTag:
			tags[column.name] = value
		default:
			v, err := strconv.ParseFloat(value, 64)
			if err != nil {
				return fmt.Errorf("unable to parse column %q: %w", column.name, err)
			}
			fields[column.name] = v
		}
	}
	if len(fields) == 0 {
		return errors.New("no value for any field")
	}
	acc.AddFields("turbostat", fields, tags, timestamp)
	return nil
}

// Creates a column struct from a Turbostat column name.
func createColumn(s string) column {
	// Add underscores around words known not to have delimiters.
	s = replacer.Replace(s)
	// Split the column name into lower case tokens.
	tokens := splitter.FindAllString(strings.ToLower(s), -1)
	// Expand abbreviations into full words.
	for i, token := range tokens {
		if replacement, found := abbreviations[token]; found {
			tokens[i] = replacement
		}
	}

	// Create and return the column.
	name := strings.Join(tokens, "_")
	switch name {
	case "time_of_day_seconds":
		return column{name: name, isTime: true}
	case "package", "node", "die", "core", "cpu", "apic", "x2apic":
		return column{name: name, isTag: true}
	default:
		return column{name: name}
	}
}

func init() {
	inputs.Add("turbostat", func() telegraf.Input {
		return &Turbostat{}
	})
}

//go:build linux && amd64

package turbostat

import (
	"flag"
	"fmt"
	"io"
	"os"
	"path/filepath"
	"testing"
	"time"

	"github.com/stretchr/testify/require"

	"github.com/influxdata/telegraf"
	"github.com/influxdata/telegraf/config"
	"github.com/influxdata/telegraf/metric"
	"github.com/influxdata/telegraf/plugins/parsers/influx"
	"github.com/influxdata/telegraf/testutil"
)

func TestCreateColumn(t *testing.T) {
	tests := []struct {
		in  string
		out column
	}{
		{in: "Core", out: column{name: "core", isTag: true}},
		{in: "Busy%", out: column{name: "busy_percent"}},
		{in: "Bzy_MHz", out: column{name: "busy_frequency_mhz"}},
		{in: "C3-", out: column{name: "c3_minus"}},
		{in: "CoreThr", out: column{name: "core_throttle"}},
		{in: "Cor_J", out: column{name: "core_energy_joule"}},
		{in: "CorWatt", out: column{name: "core_power_watt"}},
		{in: "UMHz1.0", out: column{name: "uncore_frequency_mhz_1_0"}},
		{in: "Time_Of_Day_Seconds", out: column{name: "time_of_day_seconds", isTime: true}},
	}
	for _, tt := range tests {
		t.Run(tt.in, func(t *testing.T) {
			require.Equal(t, tt.out, createColumn(tt.in))
		})
	}
}

func TestProcessValues(t *testing.T) {
	columns := []column{
		{name: "cpu", isTag: true},
		{name: "core", isTag: true},
		{name: "busy_frequency_mhz", isTag: false},
		{name: "core_power_watt", isTag: false},
	}
	tests := []struct {
		values []string
		metric telegraf.Metric
	}{
		{
			values: []string{"-", "-", "1.23", "4.56"},
			metric: metric.New(
				"turbostat",
				map[string]string{"cpu": "-", "core": "-"},
				map[string]interface{}{"busy_frequency_mhz": 1.23, "core_power_watt": 4.56},
				time.Time{},
			),
		},
		{
			values: []string{"0", "1", "1.23"},
			metric: metric.New(
				"turbostat",
				map[string]string{"cpu": "0", "core": "1"},
				map[string]interface{}{"busy_frequency_mhz": 1.23},
				time.Time{},
			),
		},
	}
	for _, tt := range tests {
		t.Run(fmt.Sprintf("%s", tt.values), func(t *testing.T) {
			acc := &testutil.Accumulator{}
			err := processValues(acc, columns, tt.values)
			require.NoError(t, err)
			actual := acc.GetTelegrafMetrics()
			testutil.RequireMetricsEqual(t, []telegraf.Metric{tt.metric}, actual, testutil.IgnoreTime())
		})
	}
}

func TestProcessValuesErrors(t *testing.T) {
	columns := []column{
		{name: "cpu", isTag: true},
		{name: "core", isTag: true},
		{name: "busy_frequency_mhz", isTag: false},
		{name: "core_power_watt", isTag: false},
	}
	tests := []struct {
		values []string
		err    string
	}{
		{
			values: []string{"0", "1"},
			err:    "no value for any field",
		},
		{
			values: []string{"0", "1", "123", "456", "789"},
			err:    "too many values: 4 columns, 5 values",
		},
		{
			values: []string{"0", "1", "xyz"},
			err:    "unable to parse column \"busy_frequency_mhz\": strconv.ParseFloat: parsing \"xyz\": invalid syntax",
		},
	}
	for _, tt := range tests {
		t.Run(fmt.Sprintf("%s", tt.values), func(t *testing.T) {
			var acc testutil.Accumulator
			err := processValues(&acc, columns, tt.values)
			require.ErrorContains(t, err, tt.err)
		})
	}
}

func TestCases(t *testing.T) {
	dirs, err := os.ReadDir("testcases")
	require.NoError(t, err)
	for _, f := range dirs {
		// Only handle directories.
		if !f.IsDir() {
			continue
		}

		testcasePath := filepath.Join("testcases", f.Name())
		configFilename := filepath.Join(testcasePath, "telegraf.conf")
		inputFilename := filepath.Join(testcasePath, "input.txt")
		expectedFilename := filepath.Join(testcasePath, "expected.out")

		t.Run(f.Name(), func(t *testing.T) {
			// Load the expected output.
			parser := &influx.Parser{}
			require.NoError(t, parser.Init())
			expected, err := testutil.ParseMetricsFromFile(expectedFilename, parser)
			require.NoError(t, err)

			// Configure the plugin.
			cfg := config.NewConfig()
			require.NoError(t, cfg.LoadConfig(configFilename))
			require.Len(t, cfg.Inputs, 1)
			plugin := cfg.Inputs[0].Input.(*Turbostat)
			require.NoError(t, plugin.Init())

			// Replace Turbostat with a mock process which outputs the desired lines.
			exe, err := os.Executable()
			require.NoError(t, err)
			plugin.command = []string{exe, "-mockInput=" + inputFilename}

			// Start the plugin and wait for the expected metrics.
			var acc testutil.Accumulator
			require.NoError(t, plugin.Start(&acc))

			require.Eventually(t, func() bool {
				return acc.NMetrics() == uint64(len(expected))
			}, 3*time.Second, 100*time.Millisecond)

			require.Empty(t, acc.Errors)

			actual := acc.GetTelegrafMetrics()
			testutil.RequireMetricsEqual(t, expected, actual, testutil.IgnoreTime())
		})
	}
}

// This function lets the test executable to behave as a mock Turbostat process.
func TestMain(m *testing.M) {
	var mockInput string
	flag.StringVar(&mockInput, "mockInput", "", "mock turbostat output")
	flag.Parse()

	if mockInput == "" {
		os.Exit(m.Run())
	}

	err := func() error {
		file, err := os.Open(mockInput)
		if err != nil {
			return err
		}
		defer file.Close()

		_, err = io.Copy(os.Stdout, file)
		if err != nil {
			return err
		}
		return nil
	}()
	if err != nil {
		os.Exit(5) // EIO
	}

	// Sleep. Terminating immediately would look like Turbostat crashed.
	time.Sleep(3 * time.Second)
}

