package turbostat

import (
	"fmt"
	"io"
	"os"
	"path/filepath"
	"strings"
	"testing"
	"time"

	"github.com/stretchr/testify/require"

	"github.com/influxdata/telegraf/config"
	"github.com/influxdata/telegraf/plugins/parsers/influx"
	"github.com/influxdata/telegraf/testutil"
)

// TestRepeatedHeaderWithDifferentWhitespace reproduces the bug where
// turbostat outputs repeated header lines with different whitespace
// from the first header, causing the exact string comparison to fail
// and "usec" (or other column names) to be parsed as float values.
func TestRepeatedHeaderWithDifferentWhitespace(t *testing.T) {
	// Create a temporary test case directory
	testDir := filepath.Join("testcases", "usec-bug")
	err := os.MkdirAll(testDir, 0755)
	require.NoError(t, err)
	defer os.RemoveAll(testDir)

	// Input: first header with tabs, repeated header with spaces
	// This simulates what happens when turbostat reformats headers
	input := strings.Join([]string{
		"usec\tTime_Of_Day_Seconds\tCore\tCPU",
		"  966\t1745932475.967756\t0\t0",
		"   54\t1745932475.966844\t1\t1",
		"usec    Time_Of_Day_Seconds     Core    CPU",
		"  100\t1745932480.974284\t0\t0",
	}, "\n") + "\n"

	inputFile := filepath.Join(testDir, "input.txt")
	require.NoError(t, os.WriteFile(inputFile, []byte(input), 0644))

	// Expected output: only the data lines, header lines skipped
	expectedContent := []string{
		"turbostat,core=0,cpu=0 time_of_day_seconds=1745932475.967756,usec=966",
		"turbostat,core=1,cpu=1 time_of_day_seconds=1745932475.966844,usec=54",
		"turbostat,core=0,cpu=0 time_of_day_seconds=1745932480.974284,usec=100",
	}
	expectedFile := filepath.Join(testDir, "expected.out")
	require.NoError(t, os.WriteFile(expectedFile, []byte(strings.Join(expectedContent, "\n")+"\n"), 0644))

	// Config
	configContent := `[[inputs.turbostat]]
  interval = "10s"
`
	configFile := filepath.Join(testDir, "telegraf.conf")
	require.NoError(t, os.WriteFile(configFile, []byte(configContent), 0644))

	// Load expected metrics
	parser := &influx.Parser{}
	require.NoError(t, parser.Init())
	expected, err := testutil.ParseMetricsFromFile(expectedFile, parser)
	require.NoError(t, err, fmt.Sprintf("Expected metrics: %+v", expected))

	// Configure plugin
	cfg := config.NewConfig()
	require.NoError(t, cfg.LoadConfig(configFile))
	require.Len(t, cfg.Inputs, 1)
	plugin := cfg.Inputs[0].Input.(*Turbostat)
	require.NoError(t, plugin.Init())

	// Replace with mock process
	exe, err := os.Executable()
	require.NoError(t, err)
	plugin.command = []string{exe, "-mockInput=" + inputFile}

	// Start plugin and verify
	var acc testutil.Accumulator
	require.NoError(t, plugin.Start(&acc))

	require.Eventually(t, func() bool {
		return acc.NMetrics() == uint64(len(expected))
	}, 3*time.Second, 100*time.Millisecond)

	// Check for errors - should have none
	require.Empty(t, acc.Errors, "Got errors: %v", acc.Errors)

	actual := acc.GetTelegrafMetrics()
	t.Logf("Got %d metrics", len(actual))
	for i, m := range actual {
		t.Logf("Metric %d: %v", i, m)
	}
	testutil.RequireMetricsEqual(t, expected, actual, testutil.IgnoreTime())
}

