	testDir := filepath.Join("testcases", "whitespace-header")
	err := os.MkdirAll(testDir, 0755)
	require.NoError(t, err)
	defer os.RemoveAll(testDir)

	// Generate input where the repeated header is completely different whitespace
	lines := []string{
		// First header (as scanner would read it)
		"usec\tBusy%\tBzy_MHz",
	}
	// 5 data lines
	for i := 0; i < 5; i++ {
		lines = append(lines, "  100\t1.23\t1200")
	}
	// Repeated header with different spacing
	lines = append(lines, "usec     Busy%   Bzy_MHz   ")
	// 5 more data lines
	for i := 0; i < 5; i++ {
		lines = append(lines, "  200\t2.34\t1300")
	}

	input := strings.Join(lines, "\n") + "\n"

	inputFile := filepath.Join(testDir, "input.txt")
	require.NoError(t, os.WriteFile(inputFile, []byte(input), 0644))

	// Config
	configContent := `[[inputs.turbostat]]
  interval = "10s"
`
	configFile := filepath.Join(testDir, "telegraf.conf")
	require.NoError(t, os.WriteFile(configFile, []byte(configContent), 0644))

	// Read the input to use as a mock
	mockData, err := os.ReadFile(inputFile)
	require.NoError(t, err)

	// Simulate what ReadStdoutFn does directly
	acc := &testutil.Accumulator{}

	turbostat := &Turbostat{}
	require.NoError(t, turbostat.Init())

	// Manually invoke the ReadStdoutFn logic
	reader := io.NopCloser(strings.NewReader(string(mockData)))

	// We can't directly test ReadStdoutFn since it's set up in Start(),
	// but we can verify the core logic by testing that a repeated header
	// with different whitespace is properly handled.
	_ = reader
	_ = acc
	_ = turbostat

	// Instead, create an integration test using the same pattern as TestCases
	cfg := config.NewConfig()
	require.NoError(t, cfg.LoadConfig(configFile))
	require.Len(t, cfg.Inputs, 1)
	plugin := cfg.Inputs[0].Input.(*Turbostat)
	require.NoError(t, plugin.Init())

	exe, err := os.Executable()
	require.NoError(t, err)
	plugin.command = []string{exe, "-mockInput=" + inputFile}

	var integrationAcc testutil.Accumulator
	require.NoError(t, plugin.Start(&integrationAcc))

	// Should have 10 data lines
	require.Eventually(t, func() bool {
		return integrationAcc.NMetrics() == 10
	}, 3*time.Second, 100*time.Millisecond)

	// No errors
	require.Empty(t, integrationAcc.Errors, "Got errors: %v", integrationAcc.Errors)
}

